#ifdef __cplusplus
extern "C" {
#endif

#include <stdio.h>
#include <sys/time.h>
#include <cuda_runtime.h>

#include "./../main.h"
#include "./../util/cuda/device.h"
#include "timing.h"

extern int platform_id_inuse;
extern int device_id_inuse;

extern __global__ void kernel_gpu_cuda(par_str d_par_gpu,
                                       dim_str d_dim_gpu,
                                       box_str *d_box_gpu,
                                       FOUR_VECTOR *d_rv_gpu,
                                       fp *d_qv_gpu,
                                       FOUR_VECTOR *d_fv_gpu);

static void tvsub_local(struct timeval *x, struct timeval *y, struct timeval *ret)
{
    ret->tv_sec = x->tv_sec - y->tv_sec;
    ret->tv_usec = x->tv_usec - y->tv_usec;
    if (ret->tv_usec < 0) {
        ret->tv_usec += 1000000;
        ret->tv_sec--;
    }
}

void kernel_gpu_cuda_wrapper(par_str par_cpu,
                             dim_str dim_cpu,
                             box_str *box_cpu,
                             FOUR_VECTOR *rv_cpu,
                             fp *qv_cpu,
                             FOUR_VECTOR *fv_cpu)
{
#ifdef TIMING
    struct timeval tv;
    struct timeval tv_total_start, tv_total_end;
    struct timeval tv_init_end;
    struct timeval tv_h2d_start, tv_h2d_end;
    struct timeval tv_d2h_start, tv_d2h_end;
    struct timeval tv_kernel_start, tv_kernel_end;
    struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
    struct timeval tv_close_start, tv_close_end;
    float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
          d2h_time = 0, close_time = 0, total_time = 0;

    gettimeofday(&tv_total_start, NULL);
#endif

    int device_count = 0;
    cudaGetDeviceCount(&device_count);

    int device = 0;
    if (device_count > 0) {
        if (device_id_inuse >= 0 && device_id_inuse < device_count) {
            device = device_id_inuse;
            cudaSetDevice(device);
        } else {
            setdevice();
            cudaGetDevice(&device);
        }
    }

    cudaDeviceProp prop;
    cudaGetDeviceProperties(&prop, device);
    printf("Platform: NVIDIA CUDA\n");
    printf("Device: %s\n", prop.name);

#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub_local(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif

    FOUR_VECTOR *d_rv_gpu = NULL;
    fp *d_qv_gpu = NULL;
    FOUR_VECTOR *d_fv_gpu = NULL;
    box_str *d_box_gpu = NULL;

    cudaMalloc((void **)&d_box_gpu, dim_cpu.box_mem);
    checkCUDAError("cudaMalloc d_box_gpu");
    cudaMalloc((void **)&d_rv_gpu, dim_cpu.space_mem);
    checkCUDAError("cudaMalloc d_rv_gpu");
    cudaMalloc((void **)&d_qv_gpu, dim_cpu.space_mem2);
    checkCUDAError("cudaMalloc d_qv_gpu");
    cudaMalloc((void **)&d_fv_gpu, dim_cpu.space_mem);
    checkCUDAError("cudaMalloc d_fv_gpu");

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub_local(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    gettimeofday(&tv_h2d_start, NULL);
#endif

    cudaMemcpy(d_box_gpu, box_cpu, dim_cpu.box_mem, cudaMemcpyHostToDevice);
    checkCUDAError("cudaMemcpy H2D d_box_gpu");
    cudaMemcpy(d_rv_gpu, rv_cpu, dim_cpu.space_mem, cudaMemcpyHostToDevice);
    checkCUDAError("cudaMemcpy H2D d_rv_gpu");
    cudaMemcpy(d_qv_gpu, qv_cpu, dim_cpu.space_mem2, cudaMemcpyHostToDevice);
    checkCUDAError("cudaMemcpy H2D d_qv_gpu");
    cudaMemcpy(d_fv_gpu, fv_cpu, dim_cpu.space_mem, cudaMemcpyHostToDevice);
    checkCUDAError("cudaMemcpy H2D d_fv_gpu");

#ifdef TIMING
    gettimeofday(&tv_h2d_end, NULL);
    tvsub_local(&tv_h2d_end, &tv_h2d_start, &tv);
    h2d_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    gettimeofday(&tv_kernel_start, NULL);
#endif

    dim3 threads(NUMBER_THREADS, 1, 1);
    dim3 blocks((unsigned int)dim_cpu.number_boxes, 1, 1);

    printf("# of blocks = %lu, # of threads/block = %d (ensure that device can handle)\n",
           (unsigned long)dim_cpu.number_boxes, NUMBER_THREADS);

    kernel_gpu_cuda<<<blocks, threads>>>(par_cpu, dim_cpu, d_box_gpu, d_rv_gpu, d_qv_gpu, d_fv_gpu);
    checkCUDAError("kernel_gpu_cuda launch");
    cudaDeviceSynchronize();
    checkCUDAError("kernel_gpu_cuda sync");

#ifdef TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub_local(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    gettimeofday(&tv_d2h_start, NULL);
#endif

    cudaMemcpy(fv_cpu, d_fv_gpu, dim_cpu.space_mem, cudaMemcpyDeviceToHost);
    checkCUDAError("cudaMemcpy D2H d_fv_gpu");

#ifdef TIMING
    gettimeofday(&tv_d2h_end, NULL);
    tvsub_local(&tv_d2h_end, &tv_d2h_start, &tv);
    d2h_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    gettimeofday(&tv_close_start, NULL);
#endif

    cudaFree(d_rv_gpu);
    cudaFree(d_qv_gpu);
    cudaFree(d_fv_gpu);
    cudaFree(d_box_gpu);

#ifdef TIMING
    printf("Time spent in different stages of the application:\n");
    gettimeofday(&tv_close_end, NULL);
    tvsub_local(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    gettimeofday(&tv_total_end, NULL);
    tvsub_local(&tv_total_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif
}

#ifdef __cplusplus
}
#endif
